import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "Compliance Monitoring",
  subtitle: "Real-time compliance scanning and automated regulatory reporting",
  description: "Stay compliant with automated monitoring for SOC 2, ISO 27001, GDPR, HIPAA, PCI-DSS, and more. Our platform continuously scans your infrastructure and generates comprehensive compliance reports with actionable remediation steps. Achieve and maintain compliance without the manual effort.",
  benefits: [
    "Real-time continuous compliance scanning",
    "Automated regulatory reporting for multiple frameworks",
    "Support for SOC 2, ISO 27001, GDPR, HIPAA, PCI-DSS",
    "Continuous compliance posture management",
    "Automated evidence collection and retention"
  ],
  features: [
    { title: "Multi-Framework Support", description: "Support for 15+ compliance frameworks" },
    { title: "Continuous Monitoring", description: "Real-time scanning instead of periodic audits" },
    { title: "Automated Reports", description: "Generate compliance reports at any time" },
    { title: "Remediation Guidance", description: "Step-by-step instructions for fixing issues" },
    { title: "Evidence Collection", description: "Automated gathering of compliance evidence" }
  ],
  howItWorks: [
    { title: "Framework Selection", description: "Choose compliance frameworks relevant to your organization" },
    { title: "Continuous Scanning", description: "Automated checks run continuously against your infrastructure" },
    { title: "Issue Detection", description: "Non-compliant configurations are identified immediately" },
    { title: "Report Generation", description: "Comprehensive reports are generated on-demand or scheduled" }
  ],
  color: "#ef4444",
  icon: "M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z",
  gradient: "from-red-500 to-rose-600"
};

function Compliance() {
  return <FeatureDetail {...pageData} />;
}

export default Compliance;
